#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_NODES 20
#define MAX_PROCESSES 10
#define MAX_RESOURCES 10

// Structure to represent the Resource Allocation Graph
typedef struct {
 int numProcesses;
 int numResources;
 int totalNodes;

 // Adjacency matrix for the graph
 // Rows 0 to numProcesses-1: Process nodes
 // Rows numProcesses to totalNodes-1: Resource nodes
 int adjMatrix[MAX_NODES][MAX_NODES];

 // Resource instances
 int resourceInstances[MAX_RESOURCES];
 int availableInstances[MAX_RESOURCES];

 // Node names for display
 char nodeNames[MAX_NODES][20];
} RAG;

// Initialize the RAG
void initRAG(RAG *rag) {
 rag->numProcesses = 0;
 rag->numResources = 0;
 rag->totalNodes = 0;

 // Initialize adjacency matrix to 0
 for (int i = 0; i < MAX_NODES; i++) {
 for (int j = 0; j < MAX_NODES; j++) {
 rag->adjMatrix[i][j] = 0;
 }
 }
}

// Add a process to the RAG
int addProcess(RAG *rag, char *name) {
 int idx = rag->totalNodes;
 strcpy(rag->nodeNames[idx], name);
 rag->totalNodes++;
 rag->numProcesses++;
 printf("Added process: %s at index %d\n", name, idx);
 return idx;
}

// Add a resource type with instances
int addResource(RAG *rag, char *name, int instances) {
 int idx = rag->totalNodes;
 strcpy(rag->nodeNames[idx], name);

 int resIdx = rag->numResources;
 rag->resourceInstances[resIdx] = instances;
 rag->availableInstances[resIdx] = instances;

 rag->totalNodes++;
 rag->numResources++;
 printf("Added resource: %s with %d instances\n", name, instances);
 return idx;
}

// Add request edge: process -> resource
void addRequestEdge(RAG *rag, int processIdx, int resourceIdx) {
 // Convert resource index to graph node index
 int graphResIdx = rag->numProcesses + resourceIdx;
 rag->adjMatrix[processIdx][graphResIdx] = 1;
 printf("Request edge: %s -> %s\n", 
 rag->nodeNames[processIdx], rag->nodeNames[graphResIdx]);
}

// Add assignment edge: resource -> process
void addAssignmentEdge(RAG *rag, int resourceIdx, int processIdx) {
 int graphResIdx = rag->numProcesses + resourceIdx;
 rag->adjMatrix[graphResIdx][processIdx] = 1;
 rag->availableInstances[resourceIdx]--;
 printf("Assignment edge: %s -> %s\n", 
 rag->nodeNames[graphResIdx], rag->nodeNames[processIdx]);
}

// DFS for cycle detection
bool dfsCycleDetect(RAG *rag, int node, bool *visited, bool *recStack, int *path, int pathLen) {
 visited[node] = true;
 recStack[node] = true;
 path[pathLen] = node;

 for (int i = 0; i < rag->totalNodes; i++) {
 if (rag->adjMatrix[node][i]) {
 if (!visited[i]) {
 if (dfsCycleDetect(rag, i, visited, recStack, path, pathLen + 1)) {
 return true;
 }
 } else if (recStack[i]) {
 // Cycle detected - print it
 printf("\n*** DEADLOCK DETECTED! ***\n");
 printf("Cycle path: ");
 for (int j = pathLen; j >= 0; j--) {
 printf("%s", rag->nodeNames[path[j]]);
 if (j > 0) printf(" -> ");
 if (path[j] == i) break;
 }
 printf(" -> %s\n", rag->nodeNames[i]);
 return true;
 }
 }
 }

 recStack[node] = false;
 return false;
}

// Main deadlock detection function
bool detectDeadlock(RAG *rag) {
 bool visited[MAX_NODES] = {false};
 bool recStack[MAX_NODES] = {false};
 int path[MAX_NODES];

 printf("\n=== Running Deadlock Detection ===\n");

 for (int i = 0; i < rag->totalNodes; i++) {
 if (!visited[i]) {
 if (dfsCycleDetect(rag, i, visited, recStack, path, 0)) {
 return true; // Deadlock found
 }
 }
 }

 printf("No deadlock detected.\n");
 return false;
}

// Print RAG state
void printRAG(RAG *rag) {
 printf("\n=== Resource Allocation Graph ===\n");
 printf("Total Nodes: %d\n", rag->totalNodes);
 printf("Processes: %d, Resources: %d\n", rag->numProcesses, rag->numResources);

 printf("\nResource Instances:\n");
 for (int i = 0; i < rag->numResources; i++) {
 printf(" %s: %d/%d available\n", 
 rag->nodeNames[rag->numProcesses + i],
 rag->availableInstances[i],
 rag->resourceInstances[i]);
 }

 printf("\nAdjacency Matrix:\n");
 printf(" ");
 for (int j = 0; j < rag->totalNodes; j++) {
 printf("%6s", rag->nodeNames[j]);
 }
 printf("\n");

 for (int i = 0; i < rag->totalNodes; i++) {
 printf("%6s", rag->nodeNames[i]);
 for (int j = 0; j < rag->totalNodes; j++) {
 printf("%6d", rag->adjMatrix[i][j]);
 }
 printf("\n");
 }
}

// Main function demonstrating deadlock detection
int main() {
 printf("=== C Resource Allocation Graph Demo ===\n");

 RAG rag;
 initRAG(&rag);

 // Create the deadlock example from textbook
 // Resources: R1, R2, R3 (1 instance each)
 addResource(&rag, "R1", 1);
 addResource(&rag, "R2", 1);
 addResource(&rag, "R3", 1);

 // Processes: P1, P2, P3
 int p1 = addProcess(&rag, "P1");
 int p2 = addProcess(&rag, "P2");
 int p3 = addProcess(&rag, "P3");

 // Initial assignments: R1->P2, R2->P3, R3->P1
 printf("\n--- Creating Initial Assignments ---\n");
 // R1 assigned to P2: edge from R1 node to P2
 rag.adjMatrix[rag.numProcesses + 0][p2] = 1; // R1 -> P2
 rag.availableInstances[0]--;

 rag.adjMatrix[rag.numProcesses + 1][p3] = 1; // R2 -> P3
 rag.availableInstances[1]--;

 rag.adjMatrix[rag.numProcesses + 2][p1] = 1; // R3 -> P1
 rag.availableInstances[2]--;

 // Requests creating deadlock: P1->R1, P2->R2, P3->R3
 printf("\n--- Creating Request Edges (Deadlock) ---\n");
 addRequestEdge(&rag, p1, 0); // P1 requests R1
 addRequestEdge(&rag, p2, 1); // P2 requests R2
 addRequestEdge(&rag, p3, 2); // P3 requests R3

 printRAG(&rag);

 // Detect deadlock
 bool hasDeadlock = detectDeadlock(&rag);

 printf("\n=== Final Result ===\n");
 if (hasDeadlock) {
 printf("Result: SYSTEM IN DEADLOCK\n");
 } else {
 printf("Result: No Deadlock\n");
 }

 return 0;
}
